        {"text_jp": "本を千匹読みました。", "furigana": "ほんをせんびきよみました。", "romaji": "Hon o senbiki yomimashita.", "translation": "Leí mil libros.", "note": "Contador incorrecto: 千匹 es para animales; los libros usan 千冊 (sensatsu).", "is_correct": False},
        {"text_jp": "千年前に私はここにいました。", "furigana": "せんねんまえにわたしはここにいました。", "romaji": "Sennen mae ni watashi wa koko ni imashita.", "translation": "Hace mil años yo estaba aquí.", "note": "Imposible: una persona no vive mil años.", "is_correct": False},
        {"text_jp": "犬が千本います。", "furigana": "いぬがせんぼんいます。", "romaji": "Inu ga senbon imasu.", "translation": "Hay mil perros.", "note": "Contador incorrecto: 千本 es para cosas largas; los animales usan 千匹 (senbiki).", "is_correct": False},
        {"text_jp": "千人いましたが、誰もいませんでした。", "furigana": "せんにんいましたが、だれもいませんでした。", "romaji": "Sennin imashita ga, dare mo imasen deshita.", "translation": "Había mil personas, pero no había nadie.", "note": "Contradicción: 千人いました (había mil) choca con 誰もいません (no había nadie).", "is_correct": False},
        {"text_jp": "花を千枚買いました。", "furigana": "はなをせんまいかいました。", "romaji": "Hana o senmai kaimashita.", "translation": "Compré mil flores.", "note": "Contador incorrecto: 千枚 es para cosas planas; las flores usan 千本 (senbon).", "is_correct": False},
        {"text_jp": "お茶を千冊飲みました。", "furigana": "おちゃをせんさつのみました。", "romaji": "Ocha o sensatsu nomimashita.", "translation": "Bebí mil tés.", "note": "Contador incorrecto: 千冊 es para libros; las bebidas usan 千杯 (senbai).", "is_correct": False},
