        {"text_jp": "空に月が三つ出ています。", "furigana": "そらにつきがみっつでています。", "romaji": "Sora ni tsuki ga mittsu dete imasu.", "translation": "Hay tres lunas en el cielo.", "note": "Falso: solo hay una 月 (luna) en el cielo.", "is_correct": False},
        {"text_jp": "来月、昨日映画を見ました。", "furigana": "らいげつ、きのうえいがをみました。", "romaji": "Raigetsu, kinō eiga o mimashita.", "translation": "El mes que viene, ayer vi una película.", "note": "Contradicción temporal: 来月 (futuro) con 昨日 (ayer) y el pasado.", "is_correct": False},
        {"text_jp": "今月は三十五日あります。", "furigana": "こんげつはさんじゅうごにちあります。", "romaji": "Kongetsu wa sanjūgo nichi arimasu.", "translation": "Este mes tiene treinta y cinco días.", "note": "Falso: ningún 月 (mes) tiene 35 días; como máximo 31.", "is_correct": False},
        {"text_jp": "月曜日の次は火月です。", "furigana": "げつようびのつぎはかげつです。", "romaji": "Getsuyōbi no tsugi wa kagetsu desu.", "translation": "Después del lunes viene 'kagetsu'.", "note": "火月 no existe; después del 月曜日 viene 火曜日.", "is_correct": False},
