        {"text_jp": "夜、太陽がよく見えます。", "furigana": "よる、たいようがよくみえます。", "romaji": "Yoru, taiyō ga yoku miemasu.", "translation": "De noche el sol se ve bien.", "note": "Error factual: el sol no se ve de noche; de noche se ven la luna y las estrellas.", "is_correct": False},
        {"text_jp": "テレビを一匹見ました。", "furigana": "テレビをいっぴきみました。", "romaji": "Terebi o ippiki mimashita.", "translation": "Vi un programa de TV.", "note": "Contador incorrecto: 一匹 es para animales; los programas de TV usan 一つ o 一本.", "is_correct": False},
        {"text_jp": "映画は来年見ました。", "furigana": "えいがはらいねんみました。", "romaji": "Eiga wa rainen mimashita.", "translation": "Vi la película el año que viene.", "note": "Contradicción temporal: 来年 (el año que viene) y 見ました (pasado) son incompatibles.", "is_correct": False},
