        {"text_jp": "日曜日は学校があります。", "furigana": "にちようびはがっこうがあります。", "romaji": "Nichiyōbi wa gakkō ga arimasu.", "translation": "El domingo hay escuela.", "note": "Error factual: el domingo (日曜日) es día libre; no hay clases.", "is_correct": False},
        {"text_jp": "体を休めると疲れます。", "furigana": "からだをやすめるとつかれます。", "romaji": "Karada o yasumeru to tsukaremasu.", "translation": "Cuando descansas el cuerpo, te cansas.", "note": "Contradicción: descansar el cuerpo (体を休める) reduce el cansancio, no lo aumenta.", "is_correct": False},
        {"text_jp": "休みを一匹取りました。", "furigana": "やすみをいっぴきとりました。", "romaji": "Yasumi o ippiki torimashita.", "translation": "Tomé un descanso.", "note": "Contador incorrecto: 一匹 es para animales; el descanso usa 一日 (ichinichi) o 一回 (ikkai).", "is_correct": False},
        {"text_jp": "夏休みは来年ありました。", "furigana": "なつやすみはらいねんありました。", "romaji": "Natsuyasumi wa rainen arimashita.", "translation": "Las vacaciones de verano fueron el año que viene.", "note": "Contradicción temporal: 来年 (el año que viene) y ありました (pasado) son incompatibles.", "is_correct": False},
